class Solution:
    def minSum(self, nums1: List[int], nums2: List[int]) -> int:
        sum1 = sum(nums1)
        sum2 = sum(nums2)
        zeros1 = nums1.count(0)
        zeros2 = nums2.count(0)

        # If both arrays have no zeros, check if sums are equal
        if zeros1 == 0 and zeros2 == 0:
            return sum1 if sum1 == sum2 else -1

        # If one array has no zeros, the other must have at least one zero
        # and the sum of the non-zero array must be less than or equal to the other
        if zeros1 == 0:
            if sum1 < sum2 + zeros2:
                return -1
            return sum1

        if zeros2 == 0:
            if sum2 < sum1 + zeros1:
                return -1
            return sum2

        # Both arrays have zeros
        # We need to make the sums equal by replacing zeros with at least 1
        # The minimum sum is max(sum1 + 1, sum2 + 1) if possible
        # But we need to ensure that the sum can be achieved with the number of zeros
        # So the minimum possible sum is max(sum1 + zeros1, sum2 + zeros2)
        return max(sum1 + zeros1, sum2 + zeros2)
